-- Table structure for material_logs
-- ----------------------------
DROP TABLE IF EXISTS `material_logs`;
CREATE TABLE `material_logs`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主キー',
  `item` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '項目',
  `material_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '製品CD',
  `material_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '製品名',
  `process_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工程CD',
  `log_date` date NOT NULL COMMENT '日付',
  `log_time` time NOT NULL COMMENT '時間',
  `hd_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'HD番号',
  `pieces_per_bundle` int NULL DEFAULT NULL COMMENT '1束あたりの本数',
  `quantity` int NULL DEFAULT NULL COMMENT '数量（pieces_per_bundle×bundle quantity）',
  `bundle_quantity` int NULL DEFAULT NULL COMMENT '束数量',
  `manufacture_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '製造番号',
  `manufacture_date` date NULL DEFAULT NULL COMMENT '製造日',
  `length` int NULL DEFAULT NULL COMMENT '長さ(mm)',
  `outer_diameter1` decimal(10, 4) NULL DEFAULT NULL COMMENT '外径1(mm)',
  `outer_diameter2` decimal(10, 4) NULL DEFAULT NULL COMMENT '外径2(mm)',
  `magnetic` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '磁気',
  `appearance` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '外観',
  `supplier` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '仕入先',
  `material_quality` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '材質',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '作成日時',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新日時',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'マック',
  `note` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '備考',
  `cutting_used_manual` tinyint(1) NOT NULL DEFAULT 0 COMMENT '手動で切断使用済と確定',
  `cutting_used_manual_at` datetime NULL DEFAULT NULL COMMENT '手動確定日時',
  `cutting_used_manual_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '手動確定ユーザー',
  `cutting_used_manual_note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '手動確定理由・備考',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_material_logs_cutting_used_manual`(`cutting_used_manual` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 279395 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

